void solve(int CASE)
{
	ll n; cin >> n;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		u++, v++;
		g[u].pb(v), g[v].pb(u);
	}

	var siz = vector<ll>(n + 1);
	var par = vector<int>(n + 1);
	var dfs = [&](var dfs, int now, int fa)->void {
		siz[now] = 1;
		par[now] = fa;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			siz[now] += siz[to];
		}
		};
	dfs(dfs, 1, 0);

	// mex 为 0 的点对
	ll ans = 0;
	for (int to : g[1])ans += siz[to] * (siz[to] - 1) / 2;
	cout << ans << ' ';

	ll tot = n * (n - 1) / 2; // 全集
	ans = tot - ans;          // 减掉 mex 为 0 的

	int x = 1, y = 1;
	int xzhi = 1, yzhi = 1; // x 端点进入的分支，y 端点进入的分支
	var vis = vector<bool>(n + 1); 
	vis[1] = 1;
	bool fail = 0;
	fa(i, 1, n - 1) { // 枚举 mex，算 ans = mex 为 i 的点对数
		int u = i + 1;

		if (vis[u] or fail)cout << 0 << ' ';
		else {
			int now = u, last = 0;
			while (!vis[now]) {
				vis[now] = 1;
				last = now;
				now = par[now];
			}

			if (now == x) {
				x = u;
				if (now == 1)xzhi = last;
			}
			else if (now == y) {
				y = u;
				if (now == 1)yzhi = last;
			}
			else fail = 1; // mex >= i + 1 的情况不存在

			// 计算 mex >= i + 1 的点对数 nex
			ll nex = 0;
			if (!fail) {
				if (x == 1) { 
					// x = 1, y = u
					// 对于 mex >= i + 1 的情况下
					// 一个端点在 siz[y] 内，另一个端点在 siz[yzhi] 外
					nex = siz[y] * (n - siz[yzhi]);
				}
				else if (y == 1) {
					// x = u, y = 1
					nex = siz[x] * (n - siz[xzhi]);
				}
				else nex = siz[x] * siz[y];
			}

			// 容斥
			// mex >= i 点对数 - mex >= i + 1 的点对数
			cout << ans - nex << " ";
			ans = nex;
		}
	}

	if (fail)cout << 0 << endl;
	else cout << 1 << endl;
	return;
}
